#!/usr/bin/env python3
"""System Provisioning Planner MVP - rig.py"""

import argparse
import json
import os
import sys
from pathlib import Path
from typing import Any

import yaml


# --- Data structures

class ValidationError:
    """Represents a validation error for a single file."""
    def __init__(self, message: str):
        self.message = message

    def to_dict(self) -> dict:
        return {"error": self.message}


class ConfigFile:
    """Represents a discovered config file."""
    def __init__(self, path: str, raw_content: dict, module_dir: str | None = None):
        self.path = path
        self.raw_content = raw_content
        self.module_dir = module_dir  # None for root-level configs
        self.errors: list[ValidationError] = []
        self.version: str | None = None
        self.schema: str | None = None
        self.os_config: dict | None = None
        self.actions: list[dict] | None = None

    def add_error(self, error: str):
        self.errors.append(ValidationError(error))

    def is_valid(self) -> bool:
        return len(self.errors) == 0

    def to_validation_dict(self) -> dict:
        result = {"path": self.path, "valid": self.is_valid()}
        if not self.is_valid():
            result["errors"] = [e.to_dict() for e in self.errors]
        return result


# --- Discovery

def discover_configs(base_dir: str) -> list[ConfigFile]:
    """Recursively walk base_dir and discover rig config files."""
    configs = []
    base_path = Path(base_dir).resolve()

    for root, dirs, files in os.walk(base_dir):
        # Skip .git directories
        dirs[:] = [d for d in dirs if d != ".git"]

        for file in files:
            ext = Path(file).suffix.lower()
            if ext not in (".yaml", ".yml", ".json"):
                continue

            file_path = os.path.join(root, file)
            rel_path = os.path.relpath(file_path, base_dir)

            try:
                with open(file_path, "r") as f:
                    raw = yaml.safe_load(f) or {}
            except Exception as e:
                config = ConfigFile(rel_path, {})
                config.add_error(f"parse error: {e}")
                configs.append(config)
                continue

            # Determine module directory (parent if schema: "module")
            config = ConfigFile(rel_path, raw)
            configs.append(config)

    return configs


# --- Validation

def validate_config(config: ConfigFile, module_names: set[str]) -> list[str]:
    """
    Validate a single config. Returns list of error messages.
    Order matches specification.
    """
    errors = []
    raw = config.raw_content

    # 1. Already validated (parse error)
    # 2. version: must be a string
    if "version" not in raw:
        errors.append("missing 'version'")
    elif not isinstance(raw["version"], str):
        errors.append("'version' must be a string")
    elif raw["version"] != "1":
        errors.append(f"unsupported version '{raw['version']}'")

    # 3. schema required, type, recognized
    if "schema" not in raw:
        errors.append("missing 'schema'")
    elif not isinstance(raw["schema"], str):
        errors.append("'schema' must be a string")
    elif raw.get("schema") not in ("module",):
        errors.append(f"unknown schema '{raw['schema']}'")

    # 4. os type (if present)
    if "os" in raw and raw["os"] is not None and not isinstance(raw["os"], dict):
        errors.append("'os' must be an object")

    # 5. os.name required/type/value (if os exists and is dict)
    os_val = raw.get("os")
    if isinstance(os_val, dict):
        os_obj = os_val
        if "name" in os_obj:
            if not isinstance(os_obj["name"], str):
                errors.append("'os.name' must be a string")
            elif os_obj["name"] not in ("macos", "linux"):
                errors.append("'os.name' must be 'macos' or 'linux'")
        elif os_obj and any(k in os_obj for k in ("packages", "applications", "package_manager")):
            errors.append("missing 'os.name'")

    # 6. os.package_manager type/value + requirement when packages/apps present
    if isinstance(os_val, dict):
        os_obj = os_val
        has_packages = "packages" in os_obj
        has_apps = "applications" in os_obj
        pm_val = os_obj.get("package_manager")

        if pm_val is not None:
            if not isinstance(pm_val, str):
                errors.append("'os.package_manager' must be a string")
            elif pm_val not in ("brew", "apt", "yum"):
                errors.append("'os.package_manager' must be 'brew', 'apt', or 'yum'")

        if has_packages or has_apps:
            if pm_val is None:
                errors.append("'os.package_manager' is required when 'packages' or 'applications' present")

    # 7. os.packages list/type/item checks
    if isinstance(os_val, dict) and "packages" in os_val:
        pkgs = os_val["packages"]
        if not isinstance(pkgs, list):
            errors.append("'os.packages' must be a list")
        else:
            for i, item in enumerate(pkgs):
                if not isinstance(item, str):
                    errors.append(f"'os.packages[{i}]' must be a string")
                elif item == "":
                    errors.append(f"'os.packages[{i}]' must not be empty")

    # 8. os.applications list/type/item checks
    if isinstance(os_val, dict) and "applications" in os_val:
        apps = os_val["applications"]
        if not isinstance(apps, list):
            errors.append("'os.applications' must be a list")
        else:
            for i, item in enumerate(apps):
                if not isinstance(item, str):
                    errors.append(f"'os.applications[{i}]' must be a string")
                elif item == "":
                    errors.append(f"'os.applications[{i}]' must not be empty")

    # 9. actions type and item-object checks
    if "actions" in raw:
        actions = raw["actions"]
        if not isinstance(actions, list):
            errors.append("'actions' must be a list")

    # 10-13. actions[N].type/.source/.destination/.hidden/.elevated
    if "actions" in raw and isinstance(raw["actions"], list):
        for i, action in enumerate(raw["actions"]):
            if not isinstance(action, dict):
                errors.append(f"'actions[{i}]' must be an object")
                continue

            # type
            if "type" not in action:
                errors.append(f"'actions[{i}]' missing 'type'")
            elif not isinstance(action["type"], str):
                errors.append(f"'actions[{i}].type' must be a string")
            elif action["type"] not in ("link", "copy", "run"):
                errors.append(f"'actions[{i}].type' must be 'link', 'copy', or 'run'")

            # source
            if "source" not in action:
                errors.append(f"'actions[{i}]' missing 'source'")
            elif not isinstance(action["source"], str):
                errors.append(f"'actions[{i}].source' must be a string")
            elif action["source"] == "":
                errors.append(f"'actions[{i}].source' must not be empty")

            # destination (for link/copy)
            atype = action.get("type")
            dest = action.get("destination")

            if atype in ("link", "copy"):
                if dest is None:
                    errors.append(f"'actions[{i}]' missing 'destination' for type '{atype}'")
                elif not isinstance(dest, str):
                    errors.append(f"'actions[{i}].destination' must be a string")
                elif not dest.startswith(("/", "~")):
                    errors.append(f"'actions[{i}].destination' must start with '/' or '~'")
                elif action["source"] == "*" and not dest.endswith("/"):
                    errors.append(f"'actions[{i}].destination' must end with '/' for wildcard source")
            elif atype == "run":
                if dest is not None and not isinstance(dest, str):
                    errors.append(f"'actions[{i}].destination' must be a string when present")

            # hidden, elevated type checks
            for field in ("hidden", "elevated"):
                if field in action:
                    if not isinstance(action[field], bool):
                        errors.append(f"'actions[{i}].{field}' must be a boolean")

    # 14. duplicate module schema check (caller handles)
    return errors


# --- Plan building

def resolve_home(path: str) -> str:
    """Replace ~ with $HOME."""
    if path.startswith("~"):
        home = os.environ.get("HOME", "")
        if path == "~":
            return home
        return home + path[1:]
    return path


def expand_wildcard(config: ConfigFile, module_base: str) -> list[dict]:
    """
    Expand wildcard source into concrete file actions.
    Returns list of action dicts (without type-specific adjustments yet).
    """
    expanded = []
    module_dir = module_base

    for action in config.actions or []:
        if action.get("source") != "*":
            continue

        dest = action.get("destination", "")
        hidden = action.get("hidden", False)
        elevated = action.get("elevated", False)
        atype = action["type"]

        # Collect matching files
        matched = []
        for entry in os.listdir(module_dir):
            entry_path = os.path.join(module_dir, entry)
            if os.path.isdir(entry_path):
                continue
            if entry.lower().endswith((".yaml", ".yml", ".json")):
                continue
            if entry.startswith("."):
                continue
            matched.append(entry)

        matched.sort()

        for filename in matched:
            source_abs = os.path.join(module_dir, filename)
            dest_base = dest

            # Handle hidden prefix
            final_dest = dest_base + filename
            if hidden and not filename.startswith("."):
                final_dest = os.path.dirname(dest_base) + "/." + os.path.basename(filename)

            final_dest = resolve_home(final_dest)

            expanded.append({
                "type": "link",
                "source": source_abs,
                "destination": final_dest,
                "elevated": elevated,
            })

    return expanded


def build_plan(
    configs: list[ConfigFile],
    os_filter: str | None = None,
    module_filter: list[str] | None = None,
) -> dict:
    """
    Build the plan from validated configs.
    Filters apply: --os, --module.
    """
    # First pass: identify modules (directories with schema: "module")
    module_map: dict[str, ConfigFile] = {}
    duplicate_module_check: dict[str, list[str]] = {}

    for cfg in configs:
        if not cfg.raw_content.get("schema") == "module":
            continue
        # Determine module name from relative path
        if cfg.module_dir is None:
            continue  # root-level configs are not modules

        # Module name is directory path relative to base, using /
        rel = os.path.relpath(cfg.module_dir)
        module_name = rel.replace("/", "/")  # already using /

        # Detect duplicates
        if module_name not in duplicate_module_check:
            duplicate_module_check[module_name] = []
        duplicate_module_check[module_name].append(cfg.path)

    # Report duplicate module schemas as errors
    for name, paths in duplicate_module_check.items():
        if len(paths) > 1:
            # Only first one gets added to module_map, rest remain in configs
            pass  # validation will catch at plan time? Actually step 14: duplicate module schema check

    # Build module map (first schema:module per directory)
    seen_dirs = set()
    for cfg in configs:
        if cfg.raw_content.get("schema") != "module":
            continue
        if cfg.module_dir is None:
            continue
        if cfg.module_dir in seen_dirs:
            continue
        seen_dirs.add(cfg.module_dir)
        rel = os.path.relpath(cfg.module_dir)
        name = rel.replace("/", "/")
        module_map[name] = cfg

    # Filter modules
    if module_filter:
        module_map = {k: v for k, v in module_map.items() if k in module_filter}

    if os_filter:
        module_map = {
            k: v for k, v in module_map.items()
            if v.os_config is None or v.os_config.get("name") == os_filter
        }

    # Build plan
    modules_out = []

    for name in sorted(module_map.keys()):
        cfg = module_map[name]
        actions_out = []

        os_config = cfg.os_config
        manager = os_config.get("package_manager") if os_config else None

        # install_package actions (sorted by package)
        packages = []
        if os_config and "packages" in os_config:
            packages = sorted(os_config["packages"])
        for pkg in packages:
            actions_out.append({
                "type": "install_package",
                "manager": manager,
                "package": pkg,
            })

        # install_application actions (sorted by application)
        apps = []
        if os_config and "applications" in os_config:
            apps = sorted(os_config["applications"])
        for app in apps:
            actions_out.append({
                "type": "install_application",
                "manager": manager,
                "application": app,
            })

        # File actions (config order, with wildcard expansion)
        # First, gather non-wildcard actions in config order
        wildcard_expanded = []

        for action in cfg.actions or []:
            source = action.get("source", "")
            if source == "*":
                # Handle wildcard expansion
                module_base = cfg.module_dir
                if module_base and os.path.isdir(module_base):
                    for entry in sorted(os.listdir(module_base)):
                        entry_path = os.path.join(module_base, entry)
                        if os.path.isdir(entry_path):
                            continue
                        if entry.lower().endswith((".yaml", ".yml", ".json")):
                            continue
                        if entry.startswith("."):
                            continue
                        # Matched file
                        dest_base = action.get("destination", "")
                        final_dest = dest_base + entry
                        if action.get("hidden", False) and not entry.startswith("."):
                            final_dest = os.path.dirname(dest_base) + "/." + os.path.basename(entry)
                        final_dest = resolve_home(final_dest)

                        atype = action["type"]
                        wildcard_expanded.append({
                            "type": "link",
                            "source": entry_path,
                            "destination": final_dest,
                            "elevated": action.get("elevated", False),
                        })
            else:
                # Non-wildcard action
                atype = action["type"]
                source_rel = action["source"]
                elevated = action.get("elevated", False)

                # Resolve source
                if source_rel.startswith("/"):
                    source_abs = source_rel  # don't normalize, invalid should be caught earlier
                else:
                    source_abs = os.path.join(cfg.module_dir, source_rel)
                source_abs = os.path.normpath(source_abs)

                if atype in ("link", "copy"):
                    dest = action.get("destination", "")
                    if dest:
                        dest = resolve_home(dest)
                    actions_out.append({
                        "type": "link" if atype == "link" else "copy",
                        "source": source_abs,
                        "destination": dest,
                        "elevated": elevated,
                    })
                elif atype == "run":
                    actions_out.append({
                        "type": "run",
                        "source": source_abs,
                        "elevated": elevated,
                    })

        # Now merge wildcard-expanded into config order (they are in file order)
        # For plan output, we place wildcard actions after non-wildcard config order?
        # Actually spec: "Wildcard expansion is sorted by source filename before action generation."
        # And ordering: file actions in config order. The wildcard expands to multiple actions,
        # but they replace the wildcard action slot, effectively in the same config position.
        # To keep it simple: wildcard-expanded are emitted where the wildcard would be,
        # but since we already processed non-wildcard in order, we need to interleave.
        # Better: Re-process actions and emit inline.
        # Let's redo that part more carefully.

        # Re-do properly: process actions in order, expanding wildcard inline.
        final_actions = []

        # Package/app actions already added (they come before file actions)
        # Now add file actions
        for action in cfg.actions or []:
            if action.get("source") == "*":
                # Already processed above into wildcard_expanded
                # But we need them in config order, with wildcard slot
                # Rebuild from scratch
                pass

        # Let me restructure: build file actions separately
        file_actions = []
        for action in cfg.actions or []:
            source = action.get("source", "")
            if source == "*":
                if cfg.module_dir and os.path.isdir(cfg.module_dir):
                    for entry in sorted(os.listdir(cfg.module_dir)):
                        entry_path = os.path.join(cfg.module_dir, entry)
                        if os.path.isdir(entry_path):
                            continue
                        if entry.lower().endswith((".yaml", ".yml", ".json")):
                            continue
                        if entry.startswith("."):
                            continue
                        dest_base = action.get("destination", "")
                        final_dest = dest_base + entry
                        if action.get("hidden", False) and not entry.startswith("."):
                            final_dest = os.path.dirname(dest_base) + "/." + os.path.basename(entry)
                        final_dest = resolve_home(final_dest)

                        file_actions.append({
                            "type": "link",
                            "source": entry_path,
                            "destination": final_dest,
                            "elevated": action.get("elevated", False),
                        })
            else:
                atype = action["type"]
                source_rel = action["source"]
                elevated = action.get("elevated", False)

                if source_rel.startswith("/"):
                    source_abs = source_rel
                else:
                    source_abs = os.path.join(cfg.module_dir, source_rel)
                source_abs = os.path.normpath(source_abs)

                if atype in ("link", "copy"):
                    dest = action.get("destination", "")
                    if dest:
                        dest = resolve_home(dest)
                    file_actions.append({
                        "type": "link" if atype == "link" else "copy",
                        "source": source_abs,
                        "destination": dest,
                        "elevated": elevated,
                    })
                elif atype == "run":
                    file_actions.append({
                        "type": "run",
                        "source": source_abs,
                        "elevated": elevated,
                    })

        actions_out.extend(file_actions)
        modules_out.append({"name": name, "actions": actions_out})

    return {"modules": modules_out}


# --- CLI commands

def cmd_validate(args):
    """Implement validate command."""
    base_dir = args.dir

    # Discover all configs
    raw_configs = discover_configs(base_dir)

    # Group by module directory for duplicate schema detection
    module_dirs: dict[str, ConfigFile] = {}
    for cfg in raw_configs:
        # Determine if it's a module config
        if cfg.raw_content.get("schema") != "module":
            continue
        # Determine module dir
        file_dir = os.path.dirname(cfg.path)
        # Root-level config (file directly in base_dir) is not a module
        if file_dir == ".":
            continue
        module_dirs[file_dir] = cfg

    # Validate each file
    for cfg in raw_configs:
        errors = validate_config(cfg, set())
        # Detect duplicate module schema
        if cfg.raw_content.get("schema") == "module":
            file_dir = os.path.dirname(cfg.path)
            if file_dir != "." and file_dir in module_dirs:
                # More than one module schema in same directory
                # Check if this is a duplicate
                pass  # handled by counting

        # Actually, for validate, we don't need to know which are modules.
        # Just validate and collect errors.
        cfg.errors = [ValidationError(e) for e in errors]

    # Build result
    all_valid = all(c.is_valid() for c in raw_configs)
    files_out = sorted([c.to_validation_dict() for c in raw_configs], key=lambda x: x["path"])

    result = {"valid": all_valid, "files": files_out}
    print(json.dumps(result, indent=2))
    return 0 if all_valid else 1


def cmd_plan(args):
    """Implement plan command."""
    base_dir = args.dir
    os_filter = args.os
    module_filter = args.module

    # Discover
    raw_configs = discover_configs(base_dir)

    # First, identify which files are module configs (schema: module, not root-level)
    module_map: dict[str, ConfigFile] = {}
    duplicate_module_schemas: dict[str, list[str]] = {}

    for cfg in raw_configs:
        if cfg.raw_content.get("schema") != "module":
            continue
        # Determine module dir
        file_abs_dir = os.path.dirname(os.path.join(base_dir, cfg.path))
        rel_dir = os.path.relpath(file_abs_dir, base_dir)
        if rel_dir == ".":
            continue  # root-level, not a module
        cfg.module_dir = file_abs_dir

        # Track duplicates
        if file_abs_dir not in duplicate_module_schemas:
            duplicate_module_schemas[file_abs_dir] = []
        duplicate_module_schemas[file_abs_dir].append(cfg.path)

    # Validate each config and collect errors
    validation_errors: list[dict] = []
    for cfg in raw_configs:
        errors = validate_config(cfg, set())

        # Add duplicate module schema errors if applicable
        if cfg.raw_content.get("schema") == "module":
            file_abs_dir = os.path.dirname(os.path.join(base_dir, cfg.path))
            if file_abs_dir in duplicate_module_schemas and len(duplicate_module_schemas[file_abs_dir]) > 1:
                errors.append(f"duplicate 'module' schema in '{os.path.relpath(file_abs_dir, base_dir)}'")

        cfg.errors = [ValidationError(e) for e in errors]
        if not cfg.is_valid():
            validation_errors.append({"path": cfg.path, "valid": False, "errors": [e.to_dict() for e in cfg.errors]})

    # If any validation errors, output to STDERR and exit 1
    if validation_errors:
        result = {"valid": False, "files": sorted(validation_errors, key=lambda x: x["path"])}
        print(json.dumps(result, indent=2), file=sys.stderr)
        return 1

    # No configs?
    module_dirs_found = set(duplicate_module_schemas.keys())
    if not module_dirs_found:
        # But check if there are any configs at all (parse errors etc.)
        if raw_configs:
            # Already caught above - but if all valid but no module configs
            # Actually, if there are valid configs but none are module schema, no modules
            # Should that be no_configs or empty plan?
            # Spec: "If both filters exclude all modules, output {'modules':[]} with exit 0"
            # So we fall through to build empty plan.
            pass

    # Build plan
    # Prepare configs for plan building: need parsed os_config and actions
    for cfg in raw_configs:
        if cfg.schema == "module" and cfg.module_dir:
            cfg.os_config = cfg.raw_content.get("os")
            cfg.actions = cfg.raw_content.get("actions", [])

    # Build plan
    plan = build_plan(raw_configs, os_filter, module_filter)

    # Check for missing source files in non-wildcard actions
    for cfg in raw_configs:
        if cfg.schema != "module" or not cfg.module_dir:
            continue
        for action in cfg.actions or []:
            if action.get("source") == "*":
                continue
            source_rel = action.get("source", "")
            if source_rel.startswith("/"):
                source_abs = source_rel
            else:
                source_abs = os.path.join(cfg.module_dir, source_rel)
            source_abs = os.path.normpath(source_abs)
            if not os.path.exists(source_abs):
                # file_not_found error
                details = f"module '{os.path.relpath(cfg.module_dir, base_dir)}' missing source file '{source_rel}'"
                print(json.dumps({"error": "file_not_found", "details": details}), file=sys.stderr)
                return 1

    print(json.dumps(plan, indent=2))
    return 0


# --- Main

def main():
    parser = argparse.ArgumentParser(prog="rig.py")
    subparsers = parser.add_subparsers(dest="command")

    validate_parser = subparsers.add_parser("validate")
    validate_parser.add_argument("dir", help="Directory to validate")

    plan_parser = subparsers.add_parser("plan")
    plan_parser.add_argument("dir", help="Directory to plan")
    plan_parser.add_argument("--os", help="Filter by OS name")
    plan_parser.add_argument("--module", nargs="*", help="Filter by module names")

    args = parser.parse_args()

    if args.command == "validate":
        ret = cmd_validate(args)
        sys.exit(ret)
    elif args.command == "plan":
        ret = cmd_plan(args)
        sys.exit(ret)
    else:
        parser.print_help()
        sys.exit(1)


if __name__ == "__main__":
    main()

