                    dest = action.get("destination", "")
                    if dest:
                        dest = resolve_home(dest)
                    actions_out.append({
                        "type": atype,
                        "source": source_abs,
                        "destination": dest,
                        "elevated": elevated,
                    })
                elif atype == "run":
                    actions_out.append({
                        "type": "run",
                        "source": source_abs,
                        "elevated": elevated,
                    })

        modules_out.append({"name": name, "actions": actions_out})

    return {"modules": modules_out}


